@* Displays a single task card with move buttons *@

<div class="task-card">
    <h4>@Task.Title</h4>
    <p class="task-assignee">@Task.Assignee</p>
    <span class="priority-badge @PriorityClass">@Task.Priority</span>
    <span class="task-due">@Task.DueDate.ToString("MMM dd")</span>
    <div class="task-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn-move" @onclick="OnMoveLeft">← Move Left</button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn-move" @onclick="OnMoveRight">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "priority-high",
        "Medium" => "priority-medium",
        "Low" => "priority-low",
        _ => ""
    };
}

@* Inline form to create a new task within a column *@

<div class="add-task-form">
    <input type="text" placeholder="Title" @bind="title" />
    <input type="text" placeholder="Assignee" @bind="assignee" />
    <select @bind="priority">
        <option value="High">High</option>
        <option value="Medium">Medium</option>
        <option value="Low">Low</option>
    </select>
    <input type="date" @bind="dueDate" />
    <div class="form-actions">
        <button class="btn-save" @onclick="Save" disabled="@saving">Save</button>
        <button class="btn-cancel" @onclick="Cancel" disabled="@saving">Cancel</button>
    </div>
    @if (!string.IsNullOrEmpty(error))
    {
        <p class="form-error">@error</p>
    }
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<TaskItem> OnTaskCreated { get; set; }
    [Parameter, EditorRequired] public EventCallback OnCancel { get; set; }
    [Parameter, EditorRequired] public string DefaultStatus { get; set; } = "";

    [Inject] private ITaskService TaskService { get; set; } = default!;

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today;
    private bool saving;
    private string? error;

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title))
        {
            error = "Title is required.";
            return;
        }

        saving = true;
        error = null;

        try
        {
            var created = await TaskService.CreateTaskAsync(title, assignee, priority, dueDate);
            await OnTaskCreated.InvokeAsync(created);
        }
        catch (Exception ex)
        {
            error = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@* A single Kanban column: header, task cards, and an add-task form toggle *@

<div class="board-column">
    <div class="column-header">
        <h3>@ColumnName</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveLeft="() => OnMoveLeft.InvokeAsync(task)"
                      OnMoveRight="() => OnMoveRight.InvokeAsync(task)" />
        }
    </div>

    @if (showForm)
    {
        <AddTaskForm DefaultStatus="@ColumnName"
                     OnTaskCreated="HandleTaskCreated"
                     OnCancel="() => showForm = false" />
    }
    else
    {
        <button class="btn-add-task" @onclick="() => showForm = true">+ Add Task</button>
    }
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskAdded { get; set; }

    private bool showForm;

    private async Task HandleTaskCreated(TaskItem task)
    {
        showForm = false;
        await OnTaskAdded.InvokeAsync(task);
    }
}

@* Search input to filter tasks by title *@

<div class="board-search">
    <input type="text"
           placeholder="Search tasks by title…"
           value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = "";
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? "");
    }
}

